function imageConvert(x){fileUI(x,async function(file,prev,msg){if(x.engine==='heic-image'){if(!w.heic2any)await loadScript('https://cdn.jsdelivr.net/npm/heic2any@0.0.4/dist/heic2any.min.js');var blob=await w.heic2any({blob:file,toType:x.toFormat==='PNG'?'image/png':'image/jpeg',quality:.92});if(Array.isArray(blob))blob=blob[0];downloadBlob(blob,file.name.replace(/\.[^.]+$/,'')+'.'+x.toFormat.toLowerCase(),prev);msg.textContent='변환이 완료되었습니다.';return}var url=URL.createObjectURL(file),img=new Image();await new Promise(function(res,rej){img.onload=res;img.onerror=rej;img.src=url});var c=d.createElement('canvas');c.width=img.naturalWidth;c.height=img.naturalHeight;var ctx=c.getContext('2d');if(x.toFormat==='JPG'){ctx.fillStyle='#fff';ctx.fillRect(0,0,c.width,c.height)}ctx.drawImage(img,0,0);var mime=x.toFormat==='PNG'?'image/png':x.toFormat==='WEBP'?'image/webp':'image/jpeg';var blob=await new Promise(function(res){c.toBlob(res,mime,.92)});downloadBlob(blob,file.name.replace(/\.[^.]+$/,'')+'.'+x.toFormat.toLowerCase(),prev);msg.textContent='브라우저에서 이미지 변환을 완료했습니다.';URL.revokeObjectURL(url)})}
